const leads = $('Read Leads').all().map((item) => item.json).filter((row) => Object.keys(row).length > 0);
const errors = $('Read ErrorLogs').all().map((item) => item.json).filter((row) => Object.keys(row).length > 0);
const now = new Date();
const dayStart = new Date(now);
dayStart.setHours(0, 0, 0, 0);
function parseDate(value) {
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? null : date;
}
function isToday(value) {
  const date = parseDate(value);
  return Boolean(date && date >= dayStart && date <= now);
}
const todayLeads = leads.filter((lead) => isToday(lead.received_at));
const todayErrors = errors.filter((error) => isToday(error.timestamp));
const priority_breakdown = { High: 0, Medium: 0, Low: 0 };
const source_counts = {};
let pending_followups = 0;
for (const lead of todayLeads) {
  if (priority_breakdown[lead.priority] !== undefined) {
    priority_breakdown[lead.priority] += 1;
  }
  const source = lead.source || 'unknown';
  source_counts[source] = (source_counts[source] ?? 0) + 1;
  if (['Draft Created', 'Needs Review'].includes(lead.follow_up_status)) {
    pending_followups += 1;
  }
}
const top_sources = Object.entries(source_counts)
  .sort(([, left], [, right]) => right - left)
  .slice(0, 5)
  .map(([source, count]) => ({ source, count }));
const error_breakdown = todayErrors.reduce((acc, error) => {
  const code = error.error_code || 'UNKNOWN_ERROR';
  acc[code] = (acc[code] ?? 0) + 1;
  return acc;
}, {});
const summary = {
  date: now.toISOString().slice(0, 10),
  generated_at: now.toISOString(),
  total_leads: todayLeads.length,
  priority_breakdown,
  error_count: todayErrors.length,
  error_breakdown,
  pending_followups,
  top_sources,
  high_priority_leads: todayLeads.filter((lead) => lead.priority === 'High').map((lead) => ({
    lead_id: lead.lead_id,
    name: lead.name,
    company: lead.company,
    source: lead.source,
    lead_score: Number(lead.lead_score ?? 0),
    recommended_next_step: lead.recommended_next_step
  }))
};
return [{ json: { summary } }];

const summary = $input.first().json.summary;
const recipient = $env.DAILY_SUMMARY_RECIPIENT;
if (!recipient) {
  throw new Error('UNKNOWN_ERROR: DAILY_SUMMARY_RECIPIENT is required.');
}
function linesFromBreakdown(breakdown) {
  const entries = Object.entries(breakdown);
  return entries.length > 0 ? entries.map(([key, value]) => `- ${key}: ${value}`).join('
') : '- none';
}
const topSources = summary.top_sources.length > 0 ? summary.top_sources.map((item) => `- ${item.source}: ${item.count}`).join('
') : '- none';
const highPriority = summary.high_priority_leads.length > 0 ? summary.high_priority_leads.map((lead) => `- ${lead.lead_id}: ${lead.name ?? lead.company ?? 'unknown'} (${lead.lead_score}) - ${lead.recommended_next_step}`).join('
') : '- none';
const text = `Daily LeadOps Summary - ${summary.date}

Totals
- leads: ${summary.total_leads}
- errors: ${summary.error_count}
- pending follow-ups: ${summary.pending_followups}

Priority breakdown
${linesFromBreakdown(summary.priority_breakdown)}

Error breakdown
${linesFromBreakdown(summary.error_breakdown)}

Top sources
${topSources}

High-priority leads
${highPriority}

Generated at: ${summary.generated_at}`;
return [{
  json: {
    summary,
    email: {
      to: recipient,
      subject: `Daily LeadOps Summary - ${summary.date}`,
      body: text
    }
  }
}];
